import React, { useState } from 'react';
import { getIrrigation } from '../context/api';

const crops = ['Rice', 'Wheat', 'Tomato', 'Maize', 'Cotton'];

const defaults = { crop: 'Rice', soil_moisture: 45, temperature: 30, humidity: 65, rain_forecast_mm: 0, field_area: 2 };

const urgencyStyle = {
  HIGH: { color: '#EF4444', tagClass: 'tag-red', bg: 'rgba(239,68,68,0.08)', border: 'rgba(239,68,68,0.3)' },
  MEDIUM: { color: '#F59E0B', tagClass: 'tag-orange', bg: 'rgba(245,158,11,0.08)', border: 'rgba(245,158,11,0.3)' },
  LOW: { color: '#22C55E', tagClass: 'tag-green', bg: 'rgba(74,222,128,0.08)', border: 'rgba(74,222,128,0.3)' },
};

export default function Irrigation() {
  const [form, setForm] = useState(defaults);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const update = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const submit = async () => {
    setLoading(true); setError(''); setResult(null);
    try {
      const res = await getIrrigation(form);
      setResult(res.data);
    } catch {
      setError('Backend not reachable. Run: cd backend && python app.py');
    }
    setLoading(false);
  };

  const s = result ? (urgencyStyle[result.urgency] || urgencyStyle.LOW) : null;

  return (
    <div className="fade-in">
      <div className="page-header">
        <div>
          <div className="page-title">💧 Smart Irrigation</div>
          <div className="page-sub">IoT sensor-based irrigation scheduling & water management</div>
        </div>
        <span className="tag tag-blue">IoT Sensors · Weather API · Time-Series Model</span>
      </div>

      {error && <div style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)', borderRadius: '10px', padding: '12px 16px', marginBottom: '20px', color: '#EF4444', fontSize: '13px' }}>⚠️ {error}</div>}

      <div className="grid-2">
        {/* Inputs */}
        <div className="card mb-20">
          <div className="section-title">📡 Sensor & Field Data</div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '14px', marginBottom: '18px' }}>
            <div style={{ gridColumn: '1 / -1' }}>
              <label>Crop Type</label>
              <select className="select" value={form.crop} onChange={e => update('crop', e.target.value)}>
                {crops.map(c => <option key={c}>{c}</option>)}
              </select>
            </div>
            {[
              { key: 'soil_moisture', label: 'Soil Moisture (%)', min: 0, max: 100 },
              { key: 'temperature', label: 'Temperature (°C)', min: 10, max: 50 },
              { key: 'humidity', label: 'Humidity (%)', min: 0, max: 100 },
              { key: 'rain_forecast_mm', label: 'Rain Forecast (mm)', min: 0, max: 100 },
              { key: 'field_area', label: 'Field Area (ha)', min: 0.1, max: 100, step: 0.1 },
            ].map(f => (
              <div key={f.key}>
                <label>{f.label}</label>
                <input type="number" className="input" value={form[f.key]}
                  min={f.min} max={f.max} step={f.step || 1}
                  onChange={e => update(f.key, parseFloat(e.target.value) || 0)} />
              </div>
            ))}
          </div>

          {/* Moisture slider visual */}
          <div style={{ background: 'var(--bg)', borderRadius: '10px', padding: '14px', marginBottom: '16px', border: '1px solid var(--border)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', fontSize: '13px' }}>
              <span style={{ color: 'var(--text-muted)' }}>Soil Moisture Level</span>
              <span style={{ fontWeight: 700, color: form.soil_moisture < 40 ? '#EF4444' : form.soil_moisture < 60 ? '#F59E0B' : '#4ADE80' }}>
                {form.soil_moisture}%
              </span>
            </div>
            <input type="range" min="0" max="100" value={form.soil_moisture}
              onChange={e => update('soil_moisture', parseInt(e.target.value))}
              style={{ width: '100%', accentColor: form.soil_moisture < 40 ? '#EF4444' : '#4ADE80' }} />
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '10px', color: '#475569', marginTop: '4px' }}>
              <span>0% Dry</span><span>50% Optimal</span><span>100% Waterlogged</span>
            </div>
          </div>

          <button className="btn btn-blue" onClick={submit} disabled={loading} style={{ width: '100%' }}>
            {loading ? <><span className="spinner" /> Calculating...</> : '💧 Get Irrigation Advice'}
          </button>
        </div>

        {/* Results */}
        <div>
          {!result && !loading && (
            <div className="card" style={{ textAlign: 'center', padding: '60px 20px', color: 'var(--text-muted)' }}>
              <div style={{ fontSize: '48px', marginBottom: '14px' }}>💧</div>
              <div style={{ fontWeight: 600 }}>Enter field data and click Analyze</div>
            </div>
          )}

          {loading && (
            <div className="card" style={{ textAlign: 'center', padding: '60px 20px' }}>
              <div className="spinner" style={{ width: '40px', height: '40px', margin: '0 auto 16px' }} />
              <div style={{ color: '#4ADE80', fontWeight: 600 }}>Calculating irrigation schedule...</div>
            </div>
          )}

          {result && (
            <div className="fade-in">
              {/* Status card */}
              <div style={{ background: s.bg, border: `1px solid ${s.border}`, borderRadius: '16px', padding: '22px', marginBottom: '16px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '14px' }}>
                  <div style={{ fontSize: '14px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px' }}>Moisture Status</div>
                  <span className={`tag ${s.tagClass}`}>{result.urgency} URGENCY</span>
                </div>
                <div style={{ fontSize: '18px', fontWeight: 800, color: s.color, marginBottom: '12px' }}>{result.moisture_status}</div>

                <div className="progress-bar" style={{ height: '12px', marginBottom: '6px' }}>
                  <div className="progress-fill" style={{ width: `${result.soil_moisture}%`, background: `linear-gradient(90deg, ${s.color}80, ${s.color})` }} />
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '11px', color: 'var(--text-muted)' }}>
                  <span>Current: {result.soil_moisture}%</span>
                  <span>Optimal: {result.optimal_range}</span>
                </div>
              </div>

              {/* Recommendation */}
              <div className="card mb-20">
                <div className="section-title">📋 Recommendation</div>
                <div style={{ padding: '14px', background: 'var(--bg)', borderRadius: '10px', border: '1px solid var(--border)', marginBottom: '12px' }}>
                  <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px' }}>Action Required</div>
                  <div style={{ fontWeight: 700, color: '#CBD5E1' }}>{result.recommended_time}</div>
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                  <div style={{ padding: '12px', background: 'var(--bg)', borderRadius: '8px', border: '1px solid var(--border)' }}>
                    <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginBottom: '4px' }}>Water Needed</div>
                    <div style={{ fontWeight: 700, color: '#3B82F6', fontSize: '18px' }}>{result.water_needed_liters}L</div>
                  </div>
                  <div style={{ padding: '12px', background: 'var(--bg)', borderRadius: '8px', border: '1px solid var(--border)' }}>
                    <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginBottom: '4px' }}>Evapotranspiration</div>
                    <div style={{ fontWeight: 700, color: '#F59E0B', fontSize: '18px' }}>{result.evapotranspiration_mm} mm</div>
                  </div>
                </div>
              </div>

              <div className="card mb-20" style={{ background: 'rgba(59,130,246,0.06)', border: '1px solid rgba(59,130,246,0.2)' }}>
                <div style={{ fontSize: '13px', color: '#3B82F6', fontWeight: 600 }}>💡 {result.water_saving_tip}</div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Weekly Schedule */}
      {result && (
        <div className="card fade-in">
          <div className="section-title">📅 7-Day Irrigation Schedule</div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '10px' }}>
            {result.weekly_schedule.map((day, i) => (
              <div key={i} style={{
                background: day.rain > 0 ? 'rgba(59,130,246,0.08)' : day.irrigate ? 'rgba(239,68,68,0.08)' : 'rgba(74,222,128,0.06)',
                border: `1px solid ${day.rain > 0 ? 'rgba(59,130,246,0.25)' : day.irrigate ? 'rgba(239,68,68,0.25)' : 'rgba(74,222,128,0.2)'}`,
                borderRadius: '12px', padding: '12px 8px', textAlign: 'center',
              }}>
                <div style={{ fontWeight: 700, fontSize: '12px', color: '#CBD5E1', marginBottom: '6px' }}>{day.date.split(' ')[0]}</div>
                <div style={{ fontSize: '10px', color: '#64748B', marginBottom: '8px' }}>{day.date.split(' ').slice(1).join(' ')}</div>
                <div style={{ fontSize: '24px', marginBottom: '6px' }}>{day.rain > 0 ? '🌧️' : day.irrigate ? '💦' : '☀️'}</div>
                <div style={{ fontSize: '11px', color: '#94A3B8' }}>{day.temp}°C</div>
                {day.rain > 0
                  ? <div style={{ fontSize: '10px', color: '#3B82F6', marginTop: '4px', fontWeight: 600 }}>Rain {day.rain}mm</div>
                  : day.irrigate
                    ? <div style={{ fontSize: '10px', color: '#EF4444', marginTop: '4px', fontWeight: 600 }}>Irrigate</div>
                    : <div style={{ fontSize: '10px', color: '#4ADE80', marginTop: '4px', fontWeight: 600 }}>Skip</div>
                }
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
